// src/components/StudentNavbar.jsx
import React from 'react';
import { NavLink, Link } from 'react-router-dom';

export default function StudentNavbar({ logout }) {
  return (
    <nav className="student-nav">
      <div className="s-nav__left">
        <Link to="/student/browse" className="navbar__logo">
          <span className="navbar__logo-icon">◈</span>
          <span>Launch<span style={{ color: 'var(--lavender)' }}>pad</span> Student</span>
        </Link>
        <div className="s-nav__links">
          <NavLink to="/student/browse" className={({ isActive }) => `s-nav__link ${isActive ? 'active' : ''}`}>Browse</NavLink>
          <NavLink to="/student/applications" className={({ isActive }) => `s-nav__link ${isActive ? 'active' : ''}`}>My Applications</NavLink>
          <NavLink to="/student/trainings" className={({ isActive }) => `s-nav__link ${isActive ? 'active' : ''}`}>My Trainings</NavLink>
        </div>
      </div>
      <div className="s-nav__user">
        <Link to="/student/profile" className="s-nav__link">My Profile</Link>
        <div className="s-avatar">JD</div>
        <button onClick={logout} className="btn btn-ghost btn-sm">Log out</button>
      </div>
    </nav>
  );
}
